+/** Re-evaluate queries which use a trait as a value-predicate dependency. */
+export function reevaluatePredicateQueries(world: World, entity: Entity, data: TraitInstance) {
+    const eid = getEntityId(entity);
+
+    for (const query of data.predicateQueries) {
+        let handledTracking = false;
+
+        for (const tracking of query.predicateTracking) {
+            if (!tracking.predicate.traits.includes(data.trait)) continue;
+
+            const values = tracking.predicate.traits.map((dependency) =>
+                getTraitInstance(world[$internal].traitInstances, dependency)
+                    ? dependency[$internal].get(eid, getTraitInstance(world[$internal].traitInstances, dependency)!.store)
+                    : undefined
+            );
+            const current = values.every((value) => value !== undefined) && matchesPredicate(tracking.predicate, values);
+            const previous = tracking.previous[eid] ?? false;
+            tracking.previous[eid] = current;
+
+            const transitioned =
+                tracking.type === 'add'
+                    ? !previous && current
+                    : tracking.type === 'remove'
+                      ? previous && !current
+                      : previous !== current;
+            if (!transitioned) {
+                if (tracking.type === 'add' && !current) query.remove(world, entity);
+                if (tracking.type === 'remove' && current) query.remove(world, entity);
+                continue;
+            }
+
+            const matches =
+                query.relationFilters && query.relationFilters.length > 0
+                    ? checkQueryWithRelations(world, query, entity)
+                    : query.check(world, entity);
+            if (matches) query.add(entity);
+            else query.remove(world, entity);
+            handledTracking = true;
+        }
+
+        if (!handledTracking && query.predicateTracking.length === 0) {
+            const matches =
+                query.relationFilters && query.relationFilters.length > 0
+                    ? checkQueryWithRelations(world, query, entity)
+                    : query.check(world, entity);
+            if (matches) query.add(entity);
+            else query.remove(world, entity);
+        }
+    }
+}
