export type IsNotModifier<T> =
    T extends Modifier<Trait[], infer TType> ? (TType extends 'not' ? true : false) : false;

export type QueryHash = string;

export type Query<T extends QueryParameter[] = QueryParameter[]> = {
    readonly [$queryRef]: true;
    /** Public read-only ID for fast array lookups */
    readonly id: number;
    /** Hash string for deduplication */
    readonly hash: QueryHash;
    /** Query parameters for creating instances */
    readonly parameters: T;
    readonly [$parameters]: T;
};

export type Modifier<TTrait extends Trait[] = Trait[], TType extends string = string> = {
    [$modifier]: true;
    type: TType;
    id: number;
    traits: TTrait;
    traitIds: number[];
};

export type PredicateValues<T extends Trait[]> = {
    [K in keyof T]: T[K] extends Trait ? TraitRecord<T[K]> : never;
};

export type Predicate<T extends Trait[] = Trait[]> = Modifier<T, 'predicate'> & {
    predicate: (values: PredicateValues<T>) => boolean;
};

/** Parameter types that can be passed to Or modifier */
export type OrParameter = Trait | Modifier;

/** Or modifier that can contain both traits and nested modifiers */
export type OrModifier<T extends OrParameter[] = OrParameter[]> = Modifier<
    ExtractTraitsFromOrParams<T>,
    'or'
> & {
import { $internal } from '../../common';
import { isRelation } from '../../relation/utils/is-relation';
import type { ExtractTraits, Trait, TraitOrRelation } from '../../trait/types';
import { universe } from '../../universe/universe';
import { createModifier } from '../modifier';
import type { Modifier } from '../types';
import type { Predicate } from '../types';
import { createTrackingId, setTrackingMasks } from '../utils/tracking-cursor';

export function createAdded() {
    const id = createTrackingId();

    for (const world of universe.worlds) {
        if (!world) continue;
        setTrackingMasks(world, id);
    }

    return ((...inputs: (TraitOrRelation | Predicate)[]) => {
        if (inputs.length === 1 && (inputs[0] as Predicate).type === 'predicate') {
            return Object.assign(createModifier(`added-${id}`, id, (inputs[0] as Predicate).traits), {
                predicate: inputs[0] as Predicate,
            });
        }
        const traits = inputs.map((input) =>
            isRelation(input) ? input[$internal].trait : input
        ) as Trait[];
        return createModifier(`added-${id}`, id, traits);
    }) as {
        <T extends TraitOrRelation[]>(...inputs: T): Modifier<ExtractTraits<T>, `added-${number}`>;
        <T extends Trait[]>(predicate: Predicate<T>): Modifier<T, `added-${number}`>;
    };
}

